from typing import List, Optional
import heapq

# Definition for singly-linked list.
class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

class Solution:
    def mergeKLists(self, lists: List[Optional[ListNode]]) -> Optional[ListNode]:
        min_heap = []
        dummy_head = ListNode(0)
        current = dummy_head

        node_id_counter = 0

        for head in lists:
            if head:
                heapq.heappush(min_heap, (head.val, node_id_counter, head))
                node_id_counter += 1

        while min_heap:
            val, _, node = heapq.heappop(min_heap)

            current.next = node
            current = current.next

            if node.next:
                heapq.heappush(min_heap, (node.next.val, node_id_counter, node.next))
                node_id_counter += 1

        return dummy_head.next
